mapper.select:
/* 실제 사용량 조회 */
select
site_id, std_timestamp, sum(usg_val) as usg_val
from (
select
usg_idx, site_id, device_id, std_timestamp, std_date, usg_val, reg_date, mod_date
from tb_usage
where site_id = #{siteId }

    and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and
    str_to_date(#{selTermTo },'%Y%m%d%H%i%s')

) a
group by site_id, std_timestamp
order by std_timestamp

/* 예측 사용량 조회 */
select
site_id, std_timestamp, sum(pre_usg_val) as pre_usg_val
from (
select
pre_usg_idx, site_id, device_id, std_timestamp, std_date, pre_usg_val, reg_date, mod_date
from tb_predict_usage
where site_id = #{siteId }

    and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and
    str_to_date(#{selTermTo },'%Y%m%d%H%i%s')

) a
group by site_id, std_timestamp
order by std_timestamp
